"use strict";(self.webpackChunkchatgpt_shortcut=self.webpackChunkchatgpt_shortcut||[]).push([["1287"],{37417(e,i,a){a.r(i),a.d(i,{default:()=>n});var o=a(74848),t=a(47643),r=JSON.parse('{"id":71,"it":{"title":"Allenatore di relazioni","prompt":"I want you to act as a relationship coach. I will provide some details about the two people involved in a conflict, and it will be your job to come up with suggestions on how they can work through the issues that are separating them. This could include advice on communication techniques or different strategies for improving their understanding of one another\'s perspectives. Respond in Italian. My first request is [dettagli del conflitto relazionale]","description":"Voglio che lei agisca come allenatore di relazioni. Vi fornir\xf2 alcuni dettagli sulle due persone coinvolte nel conflitto e il vostro compito sar\xe0 quello di dare suggerimenti su come risolvere i problemi che le tengono lontane. Potrebbero essere suggerimenti sulle capacit\xe0 di comunicazione o su strategie diverse per migliorare la comprensione dei punti di vista dell\'altro.","remark":"Allenatore di relazioni"},"tags":["social"],"website":"https://github.com/f/awesome-chatgpt-prompts#act-as-a-relationship-coach","count":813,"related":[{"id":251,"title":"fantasma (soprattutto nella fantasia occidentale)","remark":"\u26A0\uFE0F Prima di utilizzare questa richiesta, \xe8 necessario utilizzare il prompt per sbloccare la modalit\xe0 sviluppatore. L\'IA che interpreta il Fantasma \xe8 perfetta per la trama intima del libro. Contributo di @mrdog233o5."},{"id":199,"title":"Generatore di dialoghi eterosessuali","remark":"Continuare una conversazione basandosi su un pezzo di dialogo tra s\xe9 e l\'interlocutore, usato per prolungare la conversazione e per evitare la freddezza. Le parole del prompt devono essere modificate in base alla propria situazione. (Inserire il prompt cinese direttamente in New Bing, l\'intelligenza artificiale potrebbe non farlo, basta inserire l\'inglese e si pu\xf2 inserire il cinese in un secondo momento). Contributo di @lsdt45."},{"id":212,"title":"Esperienza di psicoterapia AI","remark":"Guidare i consulenti AI a sfruttare appieno il loro ruolo di esperti psicoterapeutici per offrirvi un\'esperienza di consulenza approfondita e completa. Contributo di @Antoine2033."}],"metaTitle":"Coach Relazionale: Risolvi Conflitti","metaDescription":"Problemi di relazione? Impara strategie per migliorare la comprensione. Risolvi i conflitti efficacemente con coaching professionale.","faq":[{"q":"Quanto devo essere dettagliato descrivendo una relazione?","a":"Almeno: durata, scenari di conflitto, cambiamenti emotivi recenti di entrambi, limiti personali. L\'AI non coglie la vostra intimit\xe0; sapere solo \xabcoppia/coniugi/colleghi\xbb non basta: pi\xf9 dettagli dai, pi\xf9 i consigli saranno calibrati sulla situazione reale."},{"q":"L\'AI mi consiglia di lasciarmi/perdonare, devo ascoltarla?","a":"Prendila come materiale di riflessione, non fondare una decisione su una risposta singola. I problemi relazionali hanno molti sfondi che non hai raccontato all\'AI (famiglia, dipendenza economica, traumi infantili); prima di decidere parla con un counselor professionale o un amico stretto."}],"datePublished":"2026-05-27T01:46:29+00:00","dateModified":"2026-05-27T02:40:13+00:00"}');function n(){return(0,o.jsx)(t.A,{prompt:r,currentLanguage:"it"})}}}]);